previewCss:
.darma-loader-darma-custom-380 {color: var(--loader-color, #e11d48);
  --loader-secondary-color: #fb7185;
  --loader-bg: #ffffff;
  height: 64px;
  aspect-ratio: 1.5;
  display: flex;
  gap: 8px;
}.darma-loader-darma-custom-380:before,.darma-loader-darma-custom-380:after {content: "";
  border: 8px solid var(--loader-color, #e11d48);
  border-radius: 50%;
  box-sizing: content-box;
  margin: auto;
  aspect-ratio: 1;
  animation: darma-loader-darma-custom-380-l9 infinite 1s steps(4,jump-none);
}.darma-loader-darma-custom-380:before {animation-direction: reverse;
}@keyframes darma-loader-darma-custom-380-l9 {0% {width: 0% }to {width: 75%}}

